const clampChannel = (value) => Math.max(0, Math.min(255, Number(value) || 0));

const rgbToHex = (rgbText) => {
  const [red, green, blue] = String(rgbText)
    .split(",")
    .map((channel) => clampChannel(channel).toString(16).padStart(2, "0"));
  return `#${red}${green}${blue}`;
};

const titleCase = (text) =>
  String(text)
    .toLowerCase()
    .split(/\s+/)
    .filter(Boolean)
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ");

const sortArtkalCodes = (left, right) => {
  const getFamilyRank = (code) => {
    if (code.startsWith("C") && !code.startsWith("CE")) return 0;
    if (code.startsWith("CE")) return 1;
    return 2;
  };
  const leftFamily = getFamilyRank(left.code);
  const rightFamily = getFamilyRank(right.code);
  if (leftFamily !== rightFamily) {
    return leftFamily - rightFamily;
  }
  return left.code.localeCompare(right.code, undefined, { numeric: true, sensitivity: "base" });
};

const sortHamaCodes = (left, right) => Number(left.code) - Number(right.code);

const normalizePerlerName = (name) =>
  String(name)
    .replace(/\bDK\b/g, "Dark")
    .replace(/\bLT\b/g, "Light")
    .replace(/\bCREME\b/g, "Creme")
    .replace(/\bROBIN'S\b/g, "Robin's")
    .replace(/\s+/g, " ")
    .trim();

const parseArtkalEntries = (blob) =>
  blob
    .trim()
    .split("\n")
    .map((line) => {
      const [code, rgbText] = line.split("|");
      return {
        id: `artkal-${code.toLowerCase()}`,
        code,
        name: code,
        hex: rgbToHex(rgbText),
      };
    })
    .sort(sortArtkalCodes);

const parseHamaEntries = (blob) =>
  blob
    .trim()
    .split("\n")
    .map((line) => {
      const [code, rgbText] = line.split("|");
      const paddedCode = code.padStart(2, "0");
      return {
        id: `hama-${paddedCode}`,
        code: paddedCode,
        name: `Hama ${paddedCode}`,
        hex: rgbToHex(rgbText),
      };
    })
    .sort(sortHamaCodes);

const parsePerlerEntries = (blob) =>
  blob
    .trim()
    .split("\n")
    .map((line) => {
      const [sku, rawName, rgbText] = line.split("|");
      const name = titleCase(normalizePerlerName(rawName));
      return {
        id: `perler-${sku.toLowerCase()}`,
        code: sku,
        name,
        sortKey: name,
        hex: rgbToHex(rgbText),
      };
    })
    .sort((left, right) => left.sortKey.localeCompare(right.sortKey, undefined, { sensitivity: "base" }));

